import React, { useState } from 'react';
import { motion } from 'framer-motion'; // Optional - remove if not installed
import StudentManager from './components/StudentManager';
import MovieManager from './components/MovieManager';
import './App.css'; // Legacy, will clean

function App() {
  const [activeTab, setActiveTab] = useState('movies');

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-900/80 to-slate-950 overflow-x-hidden">
      {/* Sidebar */}
      <aside className="fixed left-0 top-0 h-screen w-64 bg-slate-900/90 backdrop-blur-xl border-r border-slate-800/50 z-50 hidden lg:block">
        <div className="p-8">
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="mb-12"
          >
            <div className="flex items-center gap-4 mb-8 p-4 rounded-2xl bg-gradient-to-r from-yellow-500/10 to-orange-500/10 border border-yellow-500/20">
              <div className="w-12 h-12 bg-gradient-to-r from-yellow-400 to-orange-500 rounded-2xl flex items-center justify-center shadow-lg">
                <span className="text-2xl font-bold">🎬</span>
              </div>
              <div>
                <h1 className="text-2xl font-black bg-gradient-to-r from-yellow-400 to-orange-500 bg-clip-text text-transparent">
                  CineHub
                </h1>
                <p className="text-sm text-slate-400">Student & Movie Manager</p>
              </div>
            </div>
          </motion.div>

          {/* Navigation */}
          <nav className="space-y-2">
            {[
              { id: 'movies', icon: '🎞️', label: 'Movies', component: <MovieManager /> },
              { id: 'students', icon: '👥', label: 'Students', component: <StudentManager /> }
            ].map((item) => (
              <motion.button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                whileHover={{ x: 4, scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                className={`w-full flex items-center gap-4 p-4 rounded-xl transition-all duration-300 group ${
                  activeTab === item.id
                    ? 'bg-gradient-to-r from-yellow-500/20 to-orange-500/20 border border-yellow-400/40 text-yellow-300 shadow-lg shadow-yellow-500/20 font-semibold'
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50 border border-slate-800/50 hover:border-slate-700/50'
                }`}
              >
                <span className="text-xl">{item.icon}</span>
                <span>{item.label}</span>
                <div className={`ml-auto w-2 h-2 rounded-full transition-all ${
                  activeTab === item.id ? 'bg-yellow-400 scale-110' : 'bg-slate-600 group-hover:bg-slate-500'
                }`} />
              </motion.button>
            ))}
          </nav>
        </div>
      </aside>

      {/* Main Content */}
      <main className={`lg:ml-64 min-h-screen transition-all duration-300 ${activeTab === 'movies' ? 'bg-gradient-to-br from-slate-900/80 to-blue-900/20' : 'bg-gradient-to-br from-slate-900/80 to-emerald-900/20'}`}>
        {/* Mobile Nav */}
        <div className="lg:hidden bg-slate-900/95 backdrop-blur-xl border-b border-slate-800/50 sticky top-0 z-40">
          <div className="max-w-7xl mx-auto px-6 py-4">
            <div className="flex gap-4">
              <button
                onClick={() => setActiveTab('movies')}
                className={`flex-1 py-3 px-4 rounded-xl font-semibold transition-all ${
                  activeTab === 'movies'
                    ? 'bg-yellow-500/20 border-2 border-yellow-400/40 text-yellow-300 shadow-lg'
                    : 'bg-slate-800/50 border border-slate-700/50 text-slate-300 hover:bg-slate-700 hover:border-slate-600 hover:text-white'
                }`}
              >
                🎞️ Movies
              </button>
              <button
                onClick={() => setActiveTab('students')}
                className={`flex-1 py-3 px-4 rounded-xl font-semibold transition-all ${
                  activeTab === 'students'
                    ? 'bg-emerald-500/20 border-2 border-emerald-400/40 text-emerald-300 shadow-lg'
                    : 'bg-slate-800/50 border border-slate-700/50 text-slate-300 hover:bg-slate-700 hover:border-slate-600 hover:text-white'
                }`}
              >
                👥 Students
              </button>
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="container">
          {activeTab === 'movies' && <MovieManager />}
          {activeTab === 'students' && <StudentManager />}
        </div>
      </main>
    </div>
  );
}

export default App;
